import React from "react";
import {type ContentProps, Dialog} from "primereact/dialog";
import type {IKitsDialogControlled} from "@lmb-it/kitsconcerto-types";
import {useSeverityColors} from "../../hooks/useSeverityColors";
import {useKitsTheme} from "../../contexts/Theme";

export default function KitsDialogControlled({
                                                 state,
                                                 onHide
                                             }: IKitsDialogControlled) {
    const {
        children,
        onClose,
        asyncClose,
        type,
        icon,
        ...rest
    } = state;

    // Always call the hook (rules of hooks) — only use the result when type is set
    const severityColors = useSeverityColors(type || 'secondary');
    const colors = type ? severityColors : null;
    const {resolveToken, theme} = useKitsTheme();
    const surfaceColor = resolveToken('surface-card');
    const brandLogo = type === 'brand' ? theme.config.logo : null;

    const hide = async (event?: any) => {
        if (asyncClose && typeof onClose === "function") {
            onClose();
        } else {
            onClose?.();
        }
        onHide();
    };

    // When type (severity) is set, avoid PrimeReact's content prop so that
    // contentStyle / headerStyle are preserved by the standard dialog template.
    // Only use content prop for function children without severity.
    const getContent = () => {
        if (typeof children === "function" && !type) {
            return ({hide}: ContentProps) => children(hide);
        }
        return undefined;
    };

    // Resolve children: function children get our internal hide fn
    const resolvedChildren = typeof children === "function" ? children(hide) : children;

    return (
        <Dialog
            {...rest}
            visible={state.visible}
            onHide={hide}
            content={getContent()}
            contentStyle={{
                ...(rest?.contentStyle),
                ...(colors ? {
                    background: `linear-gradient(${colors.bgTint} 0%, ${surfaceColor} 120px)`,
                } : {}),
            }}
            headerStyle={{
                ...(rest?.headerStyle),
                ...(colors ? {
                    borderBottom: `2px solid ${colors.border}`,
                } : {}),
            }}
        >
            {/* Severity icon above content */}
            {(icon || brandLogo) && colors && (
                <div style={{
                    display: 'flex',
                    justifyContent: 'center',
                    marginBottom: 16,
                }}>
                    <div style={{
                        width: 48,
                        height: 48,
                        borderRadius: 24,
                        backgroundColor: colors.iconBg,
                        display: 'flex',
                        alignItems: 'center',
                        justifyContent: 'center',
                    }}>
                        {brandLogo ? brandLogo : typeof icon === 'string' ? (
                            <i className={icon} style={{fontSize: '1.5rem', color: colors.iconFg}}/>
                        ) : icon}
                    </div>
                </div>
            )}
            {/* When content prop is used (function children, no type), skip inline rendering */}
            {getContent() ? null : resolvedChildren}
        </Dialog>
    );
}
